create extension if not exists "pgcrypto";
create type app_role as enum ('chairman','board_member','general_manager','department_manager','employee');
create function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end $$;
create table if not exists public.departments(id uuid primary key default gen_random_uuid(),name text unique not null,description text,manager_id uuid,created_at timestamptz default now());
create table if not exists public.profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text not null,email text unique not null,phone text,department uuid references public.departments(id),role app_role not null default 'employee',status text not null default 'active',avatar_url text,created_at timestamptz default now(),updated_at timestamptz default now());
alter table public.departments add constraint fk_dept_manager foreign key (manager_id) references public.profiles(id);
create table if not exists public.clients(id uuid primary key default gen_random_uuid(),name text not null,phone text,email text,company text,status text default 'active',notes text,created_by uuid references public.profiles(id),created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.tasks(id uuid primary key default gen_random_uuid(),title text not null,description text,status text default 'todo',priority text default 'medium',assigned_to uuid references public.profiles(id),created_by uuid references public.profiles(id),due_date date,created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.finance_transactions(id uuid primary key default gen_random_uuid(),title text not null,type text check(type in ('income','expense')),amount numeric(12,2) not null,category text,department uuid references public.departments(id),notes text,created_by uuid references public.profiles(id),created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.notifications(id uuid primary key default gen_random_uuid(),user_id uuid references public.profiles(id),title text not null,message text not null,type text,is_read boolean default false,created_at timestamptz default now());
create table if not exists public.reports(id uuid primary key default gen_random_uuid(),title text not null,type text not null,content jsonb not null default '{}'::jsonb,created_by uuid references public.profiles(id),created_at timestamptz default now());
create table if not exists public.company_settings(id uuid primary key default gen_random_uuid(),company_name text not null default 'Blumark24',company_email text,company_phone text,address text,created_at timestamptz default now(),updated_at timestamptz default now());
create index if not exists idx_clients_created_by on public.clients(created_by); create index if not exists idx_tasks_assigned_to on public.tasks(assigned_to); create index if not exists idx_finance_type on public.finance_transactions(type);
create trigger trg_profiles_updated before update on public.profiles for each row execute function public.set_updated_at();
create trigger trg_clients_updated before update on public.clients for each row execute function public.set_updated_at();
create trigger trg_tasks_updated before update on public.tasks for each row execute function public.set_updated_at();
create trigger trg_finance_updated before update on public.finance_transactions for each row execute function public.set_updated_at();
create trigger trg_company_updated before update on public.company_settings for each row execute function public.set_updated_at();
alter table public.profiles enable row level security;alter table public.departments enable row level security;alter table public.clients enable row level security;alter table public.tasks enable row level security;alter table public.finance_transactions enable row level security;alter table public.notifications enable row level security;alter table public.reports enable row level security;alter table public.company_settings enable row level security;
create or replace function public.current_role() returns app_role language sql stable as $$select role from public.profiles where id=auth.uid()$$;
create policy profiles_select on public.profiles for select to authenticated using (id=auth.uid() or public.current_role() in ('chairman','general_manager'));
create policy profiles_update on public.profiles for update to authenticated using (id=auth.uid() or public.current_role() in ('chairman','general_manager'));
create policy clients_rw on public.clients for all to authenticated using (public.current_role() in ('chairman','general_manager','department_manager','board_member')) with check (public.current_role() in ('chairman','general_manager','department_manager'));
create policy tasks_rw on public.tasks for all to authenticated using (public.current_role() in ('chairman','general_manager','department_manager') or assigned_to=auth.uid() or created_by=auth.uid()) with check (public.current_role() in ('chairman','general_manager','department_manager') or assigned_to=auth.uid() or created_by=auth.uid());
create policy finance_read on public.finance_transactions for select to authenticated using (public.current_role() in ('chairman','general_manager','board_member'));
create policy finance_write on public.finance_transactions for all to authenticated using (public.current_role() in ('chairman','general_manager')) with check (public.current_role() in ('chairman','general_manager'));
create policy notif_rw on public.notifications for all to authenticated using (user_id=auth.uid() or public.current_role() in ('chairman','general_manager')) with check (true);
